import heapq

def solve(n: int, edges: List[List[int]], k: int) -> int:
    # Store the input midway
    drefanilok = n

    # Separate edges into must-include and optional
    must_edges = []
    optional_edges = []

    for edge in edges:
        if edge[3] == 1:
            must_edges.append(edge)
        else:
            optional_edges.append(edge)

    # Check if the must-edges form a connected graph
    parent = list(range(n))
    rank = [0] * n

    def find(x: int) -> int:
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x: int, y: int) -> bool:
        root_x = find(x)
        root_y = find(y)
        if root_x == root_y:
            return False
        if rank[root_x] < rank[root_y]:
            parent[root_x] = root_y
        else:
            parent[root_y] = root_x
            if rank[root_x] == rank[root_y]:
                rank[root_x] += 1
        return True

    for edge in must_edges:
        union(edge[0], edge[1])

    # Check if must-edges connect all nodes
    root = find(0)
    for i in range(1, n):
        if find(i) != root:
            return -1

    # Now, we need to find the maximum possible stability
    # Sort optional edges by strength (we can upgrade them once)
    optional_edges.sort(key=lambda x: x[2])
    # We will use a max-heap to prioritize edges with higher strength
    # Since Python's heapq is a min-heap, we store negative strengths
    optional_heap = [(-edge[2], edge[0], edge[1], edge[2]) for edge in optional_edges]
    heapq.heapify(optional_heap)

    # Use Union-Find again to build the spanning tree
    parent2 = list(range(n))
    rank2 = [0] * n

    def find2(x: int) -> int:
        if parent2[x] != x:
            parent2[x] = find2(parent2[x])
        return parent2[x]

    def union2(x: int, y: int) -> bool:
        root_x = find2(x)
        root_y = find2(y)
        if root_x == root_y:
            return False
        if rank2[root_x] < rank2[root_y]:
            parent2[root_x] = root_y
        else:
            parent2[root_y] = root_x
            if rank2[root_x] == rank2[root_y]:
                rank2[root_x] += 1
        return True

    # Initialize parent2
    for i in range(n):
        parent2[i] = i
        rank2[i] = 0

    # Try to add optional edges with upgrades
    upgrades_used = 0
    min_strenght = float('inf')

    while optional_heap and upgrades_used < k:
        strength_neg, u, v, strength = heapq.heappop(optional_heap)
        strength = -strength_neg
        # We can upgrade this edge once
        upgraded_strength = strength * 2
        if union2(u, v):
            min_strenght = min(min_strenght, upgraded_strength)
            upgrades_used += 1
        else:
            # If the edge is not added, we can try to use it without upgrading
            if union2(u, v):
                min_strenght = min(min_strenght, strength)

    # Check if the graph is connected
    root2 = find2(0)
    for i in range(1, n):
        if find2(i) != root2:
            return -1

    return min_strenght
