            must_edges.push_back(edge);
        } else {
            optional_edges.push_back(edge);
        }
    }

    // Check if the must-edges form a connected graph
    // We can use Union-Find (Disjoint Set Union) for this
    vector<long long> parent(n);
    vector<long long> rank(n);

    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    auto union_find = [&](long long x, long long y) -> bool {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x == root_y) {
            return false;
        }
        if (rank[root_x] < rank[root_y]) {
            parent[root_x] = root_y;
        } else {
            parent[root_y] = root_x;
            if (rank[root_x] == rank[root_y]) {
                rank[root_x]++;
            }
        }
        return true;
    };

    for (auto& edge : must_edges) {
        union_find(edge[0], edge[1]);
    }

    // Check if must-edges connect all nodes
    long long root = find(0);
    for (long long i = 1; i < n; ++i) {
        if (find(i) != root) {
            return -1;
        }
    }

    // Now, we need to find the maximum possible stability
    // We can use a modified Kruskal's algorithm, where we prioritize edges with higher strength
    // But we also need to consider the optional edges that can be upgraded

    // Sort optional edges by strength (we can upgrade them once)
    sort(optional_edges.begin(), optional_edges.end(), [](vector<long long> a, vector<long long> b) {
        return a[2] < b[2];
    });

    // Reverse to sort in descending order
    reverse(optional_edges.begin(), optional_edges.end());

    // Use Union-Find again to build the spanning tree
    vector<long long> parent2(n);
    vector<long long> rank2(n);

    auto find2 = [&](long long x) -> long long {
        if (parent2[x] != x) {
            parent2[x] = find2(parent2[x]);
        }
        return parent2[x];
    };

    auto union_find2 = [&](long long x, long long y) -> bool {
        long long root_x = find2(x);
        long long root_y = find2(y);
        if (root_x == root_y) {
            return false;
        }
        if (rank2[root_x] < rank2[root_y]) {
            parent2[root_x] = root_y;
        } else {
            parent2[root_y] = root_x;
            if (rank2[root_x] == rank2[root_y]) {
                rank2[root_x]++;
            }
        }
        return true;
    };

    // Initialize parent2
    for (long long i = 0; i < n; ++i) {
        parent2[i] = i;
        rank2[i] = 0;
    }

    // Try to add optional edges with upgrades
    long long upgrades_used = 0;
    long long min_strenght = 0;

    for (auto& edge : optional_edges) {
        if (upgrades_used >= k) {
            break;
        }
        // We can upgrade this edge once
        long long strength = edge[2] * 2;
        if (union_find2(edge[0], edge[1])) {
            min_strenght = min(min_strenght, strength);
            upgrades_used++;
        } else {
            // If the edge is not added, we can try to use it without upgrading
            if (union_find2(edge[0], edge[1])) {
                min_strenght = min(min_strenght, edge[2]);
            }
        }
    }

    // Check if the graph is connected
    long long root2 = find2(0);
    for (long long i = 1; i < n; ++i) {
        if (find2(i) != root2) {
            return -1;
        }
    }

    return min_strenght;
}
